const fs = require('fs');
const contractContent = fs.readFileSync('/Users/jhoetter/repos/bim-ai/packages/web/src/tools/authoringCommandContract.ts', 'utf8');
const toolRegContent = fs.readFileSync('/Users/jhoetter/repos/bim-ai/packages/web/src/tools/toolRegistry.ts', 'utf8');

// Extract ToolId union members
const toolIdSection = toolRegContent.match(/export type ToolId =\n([\s\S]*?);\n/);
const toolIds = toolIdSection[1].match(/'[\\w-]+'/g).map(s => s.replace(/'/g, ''));

// Extract keys from AUTHORING_COMMAND_CONTRACTS - more robust pattern
const contractSection = contractContent.match(/export const AUTHORING_COMMAND_CONTRACTS = \{([\s\S]*?)\} satisfies/);
const contractKeys = [];
if (contractSection) {
  const re = /^\s{2}'?([\\w-]+)'?:\s*contract\(/gm;
  let m;
  while ((m = re.exec(contractSection[1])) !== null) {
    contractKeys.push(m[1]);
  }
}

const missing = toolIds.filter(id => !contractKeys.includes(id));
console.log('ToolIds:', toolIds.length, 'Contract keys:', contractKeys.length);
console.log('Missing from contract:');
missing.forEach(id => console.log(' -', id));
console.log('Contract includes beam-system?', contractKeys.includes('beam-system'));
"

