export function paletteForMode(mode: WorkspaceMode, t: TFunction): ToolDefinition[] {
  const registry = getToolRegistry(t);
  return PALETTE_ORDER.map((id) => registry[id]).filter((tool) => tool.modes.includes(mode));
}

export interface ToolDisabledContext {
  hasAnyWall: boolean;
  hasAnyFloor: boolean;
  hasAnySelection: boolean;
}

export function isToolDisabled(
  toolId: ToolId,
  ctx: ToolDisabledContext,
  t: TFunction,
): { disabled: boolean; reason?: string } {
  switch (toolId) {
    case 'floor':
      return { disabled: false };
    case 'floor-sketch':
      // Sketch mode authors a floor from a boundary loop; it does not depend on walls.
      return { disabled: false };
    case 'roof-sketch':
    case 'room-separation-sketch':
      // Sketch mode draws into a free space; no element preconditions.
      return { disabled: false };
    case 'roof':
      return { disabled: false };
    case 'railing':
      if (!ctx.hasAnyFloor && !ctx.hasAnyWall) {
        return { disabled: true, reason: t('tools.disabled.addStairFirst') };
      }
      return { disabled: false };
    case 'dimension':
      if (!ctx.hasAnyWall)
        return { disabled: true, reason: t('tools.disabled.nothingToDimension') };
      return { disabled: false };
    default:
      return { disabled: false };
  }
}

function buildToolCapabilities(): CommandCapability[] {
  return Object.values(getToolRegistry(IDENTITY_T)).map((tool) => {
    const contract = getAuthoringCommandContract(tool.id);
    return {
      id: `tool.${tool.id}`,
      label: labelForTool(tool),
      owner: 'tools/toolRegistry',
      group: groupForTool(tool.id),
      scope: 'view',
      intendedModes: [...tool.modes],
      surfaces: ['ribbon', 'cmd-k'],
      executionSurface: executionSurfaceForTool(tool),
      preconditions: [...new Set([...preconditionsForTool(tool.id), ...contract.requiredContext])],
      status: 'implemented',
      usabilityScore: 8,
      lifecycleKind: contract.kind,
      completionBehavior: contract.completionBehavior,
      previewSemantics: contract.previewSemantics,
      bridgeToMode: bridgeModesForTool(tool),
      notes: tool.tooltip,
    };
  });
}

