  rectMm: { xMm: 0, yMm: 0, widthMm: 1000, heightMm: 1000 },
  rotationDeg: 0,
  opacity: 1,
  lockedScale: false,
};

function makeDefaultProps(elements: Element[] = [viewpointEl, savedViewEl, scheduleEl]) {
  return {
    elements,
    activeViewId: null as string | null,
    onActivateView: vi.fn(),
