      positionMm: { xMm: 0, yMm: 0 },
      levelId: 'lvl-0',
      elevationViewIds: { north: 'n', south: 's', east: 'e', west: 'w' },
    };
    expect(minimal.radiusMm).toBeUndefined();
  });
});

